script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, null, null, 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {
  &ScriptActiveVoucher;
  f.setReferenceKeyFilter('ma_tn');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {
  &ScriptScatterVoucher;
  f.setReferenceKeyFilter('ma_tn');
}
function close$Voucher$(f) {
  &ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d06')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d06')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tn_ct_nt : t_tn_ct');
    v.addGridFields(g, 'tn_ct_nt : tn_ct');
    v.addTotalFields(g, [['t_tn_ct_nt', 'tn_ct_nt'], ['t_tn_ct', 'tn_ct']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tn_ct_nt]:=[t_tn_ct_nt]', '[t_tn_ct]:=[t_tn_ct]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d06', 'ma_tn']&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}

      /* <flatten type="Javascript"> */
function onChange$Voucher$VoucherDate(o) {o.parentForm.getItem('ngay_ct').value = o.parentForm.getItem('ngay_lct').value;}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

     default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d06'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$VoucherType(o) {
  var f = o.parentForm, g = f.getItem("d06")._controlBehavior, c = 'ma_nv';
  var o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
  f.setReferenceKeyFilter('ma_tn');
}
/* </flatten> */

      &ListScript;
      &PostScript;
